
const DEFAULT_LOGO='data:image/png;base64,';
const blank={orders:[],expenses:[],inventory:[],customers:[],invoices:[],settings:{businessName:'Eternal Blooms',businessUser:'@eternalblooms.ie',logoData:DEFAULT_LOGO,invoicePolicy:'A booking is confirmed once the agreed retainer is received. The remaining balance is due by the date agreed with the florist. Changes and cancellations are subject to the florist’s written terms and applicable consumer law.'},version:'1.4.0'};
let db;try{db=JSON.parse(localStorage.ebFloristStudioConnected||'null')||structuredClone(blank)}catch(e){db=structuredClone(blank)}normalize();
let localFileHandle=null, localFileName='';
const pages=[['home','Home','🏠'],['calculator','Calc','🧮'],['orders','Orders','📋'],['inventory','Stock','📦'],['expenses','Expenses','💸'],['calendar','Calendar','📅'],['customers','Customers','👥'],['invoices','Invoices','🧾'],['content','Ideas','💡'],['analytics','Stats','📈']];
function $(id){return document.getElementById(id)}function money(n){return '€'+Number(n||0).toFixed(2)}function today(){return new Date().toISOString().slice(0,10)}function val(id){return parseFloat($(id).value)||0}function esc(s){return String(s??'').replace(/[&<>"]/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[m]))}
function normalize(){['orders','expenses','inventory','customers','invoices'].forEach(k=>db[k] ||= []);db.settings ||= {};db.settings.businessName ||= 'Eternal Blooms';db.settings.businessUser ||= '@eternalblooms.ie';db.settings.logoData ||= DEFAULT_LOGO;db.settings.invoicePolicy ||= 'A booking is confirmed once the agreed retainer is received. The remaining balance is due by the date agreed with the florist. Changes and cancellations are subject to the florist’s written terms and applicable consumer law.';db.orders.forEach(o=>{o.depositPaid=!!o.depositPaid;o.depositAmount=Math.max(0,+o.depositAmount||0)});db.invoices.forEach(i=>{i.depositPaid=!!i.depositPaid;i.depositAmount=Math.max(0,+i.depositAmount||0)})}
function save(){normalize();localStorage.ebFloristStudioConnected=JSON.stringify(db);render();saveToLocalFile(true)}
function showPage(id){document.querySelectorAll('.page').forEach(p=>p.classList.toggle('active',p.id===id));document.querySelectorAll('[data-page]').forEach(b=>b.classList.toggle('active',b.dataset.page===id));window.scrollTo(0,0)}
function setupNav(){nav.innerHTML=bottomNav.innerHTML=pages.map(p=>`<button data-page="${p[0]}" onclick="showPage('${p[0]}')"><span>${p[2]}</span> ${p[1]}</button>`).join('');document.querySelectorAll('[data-page="home"]').forEach(b=>b.classList.add('active'))}
function supportsFiles(){return 'showSaveFilePicker' in window && 'showOpenFilePicker' in window}async function writeFile(h,data){const w=await h.createWritable();await w.write(JSON.stringify(data,null,2));await w.close()}
async function createLocalFile(){if(!supportsFiles())return alert('This browser cannot connect directly to a local file. Use Download backup / Import backup instead.');try{localFileHandle=await showSaveFilePicker({suggestedName:'florist-studio-data.json',types:[{description:'Florist Studio data',accept:{'application/json':['.json']}}]});localFileName=localFileHandle.name;await writeFile(localFileHandle,db);fileStatus.textContent='Connected to '+localFileName+'.'}catch(e){fileStatus.textContent='No file created.'}}
async function openLocalFile(){if(!supportsFiles())return alert('This browser cannot open/save a local file directly. Use Download backup / Import backup instead.');try{[localFileHandle]=await showOpenFilePicker({types:[{description:'Florist Studio data',accept:{'application/json':['.json']}}],multiple:false});localFileName=localFileHandle.name;const f=await localFileHandle.getFile();db=JSON.parse(await f.text()||'{}');normalize();localStorage.ebFloristStudioConnected=JSON.stringify(db);fileStatus.textContent='Connected to '+localFileName+'.';render()}catch(e){fileStatus.textContent='No file opened.'}}
async function saveToLocalFile(silent=false){if(!localFileHandle){if(!silent)fileStatus.textContent='No local file connected yet.';return}try{await writeFile(localFileHandle,db);if(!silent)fileStatus.textContent='Saved to '+localFileName+' at '+new Date().toLocaleTimeString()}catch(e){if(!silent)fileStatus.textContent='Could not save to file. Download a backup.'}}
function exportData(){let a=document.createElement('a');a.href=URL.createObjectURL(new Blob([JSON.stringify(db,null,2)],{type:'application/json'}));a.download='florist-studio-backup.json';a.click();setTimeout(()=>URL.revokeObjectURL(a.href),500)}
importFile.onchange=e=>{let r=new FileReader();r.onload=()=>{db=JSON.parse(r.result);normalize();save();fileStatus.textContent='Backup imported.'};r.readAsText(e.target.files[0])};
function saveBrand(){db.settings.businessName=businessName.value||'My Florist Studio';db.settings.businessUser=businessUser.value||'';db.settings.invoicePolicy=invoicePolicy.value.trim()||db.settings.invoicePolicy;save()}function resetBrand(){db.settings={businessName:'Eternal Blooms',businessUser:'@eternalblooms.ie',logoData:DEFAULT_LOGO,invoicePolicy:'A booking is confirmed once the agreed retainer is received. The remaining balance is due by the date agreed with the florist. Changes and cancellations are subject to the florist’s written terms and applicable consumer law.'};save()}logoFile.onchange=e=>{let f=e.target.files[0];if(!f)return;let r=new FileReader();r.onload=()=>{db.settings.logoData=r.result;save()};r.readAsDataURL(f)};
function customerOptions(){let opts='<option value="">No customer selected</option>'+db.customers.map(c=>`<option value="${c.id}">${esc(c.name)}</option>`).join('');calcCustomer.innerHTML=orderCustomer.innerHTML=opts}
function stockOptions(selected=''){return '<option value="">Choose stock</option>'+db.inventory.map(i=>`<option value="${i.id}" ${String(i.id)===String(selected)?'selected':''}>${esc(i.name)} (${i.qty} ${esc(i.unit)} · ${money(i.cost)})</option>`).join('')}
function addCalcLine(itemId='',qty=1){let div=document.createElement('div');div.className='lineitem';div.innerHTML=`<div><label>Stock item</label><select onchange="calc()">${stockOptions(itemId)}</select></div><div><label>Qty used</label><input type="number" min="0" step="0.1" value="${qty}" oninput="calc()"></div><button class="danger" onclick="this.parentElement.remove();calc()">Remove</button>`;calcItems.appendChild(div);calc()}
function getCalcStock(){return [...calcItems.querySelectorAll('.lineitem')].map(row=>{let id=+row.querySelector('select').value, qty=+row.querySelector('input').value||0, item=db.inventory.find(i=>i.id===id);return item&&qty?{id,name:item.name,qty,unit:item.unit,cost:+item.cost||0,total:qty*(+item.cost||0)}:null}).filter(Boolean)}
function calc(){let stock=getCalcStock(), stockCost=stock.reduce((a,i)=>a+i.total,0), base=stockCost+val('labour')+val('supplies'), price=base*(1+val('markup')/100)+val('fees'), profit=price-base;cStock.textContent=money(stockCost);cPrice.textContent=money(price);cProfit.textContent=money(profit);return{stock,stockCost,base,price,profit}}
['labour','supplies','markup','fees'].forEach(id=>setTimeout(()=>$(id).addEventListener('input',calc),0));
function reserveStock(stock){stock.forEach(s=>{let item=db.inventory.find(i=>i.id===s.id);if(item)item.qty=Math.max(0,(+item.qty||0)-(+s.qty||0))})}
function orderStatus(o){if(o.manualStatus==='Done'||o.manualStatus==='Not done')return o.manualStatus;return (o.date||today())<today()?'Done':'Not done'}
function saveCalcAsOrder(){let c=calc();let customer=db.customers.find(x=>String(x.id)===String(calcCustomer.value));let order={id:Date.now(),name:calcName.value||'Bouquet order',date:calcDate.value||today(),price:c.price,cost:c.base,customerId:calcCustomer.value||'',customerName:customer?customer.name:'',notes:calcNotes.value,stockUsed:c.stock,fromCalculator:true,depositPaid:false,depositAmount:0};reserveStock(c.stock);db.orders.push(order);save();alert('Saved as order and connected to stock.')}function clearCalc(){calcName.value=calcNotes.value='';calcItems.innerHTML='';['labour','supplies','fees'].forEach(id=>$(id).value=0);markup.value=100;addCalcLine();calc()}
function addManualOrder(){let customer=db.customers.find(x=>String(x.id)===String(orderCustomer.value)),deposit=Math.min(val('orderDepositAmount'),val('orderPrice'));db.orders.push({id:Date.now(),name:orderName.value||'Order',date:orderDate.value||today(),price:val('orderPrice'),cost:val('orderCost'),customerId:orderCustomer.value||'',customerName:customer?customer.name:'',manualStatus:orderStatus.value==='Auto by date'?'':orderStatus.value,notes:orderNotes.value,stockUsed:[],depositPaid:orderDepositPaid.checked,depositAmount:deposit});orderName.value=orderPrice.value=orderCost.value=orderNotes.value=orderDepositAmount.value='';orderDepositPaid.checked=false;save()}
function addInventory(){db.inventory.push({id:Date.now(),name:iName.value||'Stock item',cat:iCat.value,qty:val('iQty'),unit:iUnit.value||'items',cost:val('iCost'),min:val('iMin')});iName.value=iQty.value=iUnit.value=iCost.value=iMin.value='';save()}function adjInv(id,n){let i=db.inventory.find(x=>x.id===id);if(i)i.qty=Math.max(0,(+i.qty||0)+n);save()}function addExpense(){db.expenses.push({id:Date.now(),name:eName.value||'Expense',date:eDate.value||today(),amount:val('eAmount'),cat:eCat.value});eName.value=eAmount.value='';save()}function addCustomer(){db.customers.push({id:Date.now(),name:cuName.value||'Customer',phone:cuPhone.value,email:cuEmail.value,pref:cuPref.value,notes:cuNotes.value});cuName.value=cuPhone.value=cuEmail.value=cuPref.value=cuNotes.value='';save()}function addInvoice(){let total=val('invAmount'),deposit=Math.min(val('invDepositAmount'),total);db.invoices.push({id:Date.now(),customer:invCustomer.value||'Customer',date:invDate.value||today(),item:invItem.value||'Bouquet',amount:total,depositAmount:deposit,depositPaid:invDepositPaid.checked,status:invStatus.value,orderId:''});invCustomer.value=invItem.value=invAmount.value=invDepositAmount.value='';invDepositPaid.checked=false;save()}
function invoiceFromOrder(){let o=db.orders.find(x=>String(x.id)===String(invoiceOrder.value));if(!o)return alert('Choose an order first.');let deposit=Math.min(+o.depositAmount||0,+o.price||0),balance=Math.max(0,(+o.price||0)-deposit);db.invoices.push({id:Date.now(),customer:o.customerName||'Customer',date:today(),item:o.name,amount:+o.price||0,depositAmount:deposit,depositPaid:!!o.depositPaid,status:balance<=0&&o.depositPaid?'Paid':(o.depositPaid&&deposit>0?'Part-paid':'Unpaid'),orderId:o.id});save();showPage('invoices')}
function del(type,id){db[type]=db[type].filter(x=>x.id!==id);save()}
function invoiceHTML(i){let biz=esc(db.settings.businessName),user=esc(db.settings.businessUser),logo=db.settings.logoData||DEFAULT_LOGO,deposit=Math.min(+i.depositAmount||0,+i.amount||0),balance=Math.max(0,(+i.amount||0)-deposit),policy=esc(db.settings.invoicePolicy||'');return `<!doctype html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Invoice</title><style>:root{--ink:#241d19;--muted:#756b63;--line:#eadfd5;--blush:#f7e6e5;--sage:#eaf1e8}*{box-sizing:border-box}body{font-family:Inter,-apple-system,BlinkMacSystemFont,"Segoe UI",Arial,sans-serif;background:linear-gradient(145deg,#fbf7f1,#fff);color:var(--ink);margin:0;padding:24px}.invoice{max-width:840px;margin:auto;background:white;border:1px solid var(--line);border-radius:30px;padding:38px;box-shadow:0 24px 70px rgba(57,42,32,.10)}.top{display:flex;justify-content:space-between;gap:22px;border-bottom:1px solid var(--line);padding-bottom:22px}.brand{display:flex;gap:16px;align-items:center}.brand img{width:86px;height:86px;object-fit:contain;border-radius:22px}.brand h1{margin:0 0 6px;font-family:Georgia,serif;font-size:32px}.muted{color:var(--muted)}.box{border:1px solid var(--line);border-radius:20px;padding:18px;margin:20px 0;background:#fffdf9}table{width:100%;border-collapse:collapse}td,th{padding:15px;border-bottom:1px solid var(--line);text-align:left}.money{text-align:right}.payment-summary{margin:22px 0 0 auto;max-width:390px;border:1px solid var(--line);border-radius:22px;overflow:hidden}.payment-row{display:flex;justify-content:space-between;padding:13px 16px;border-bottom:1px solid var(--line)}.payment-row:last-child{border:0;background:var(--blush);font-size:20px;font-weight:900}.paid{display:inline-block;padding:6px 10px;border-radius:999px;background:var(--sage);font-weight:800}.unpaid{background:#fff2ec}.policy{margin-top:28px;padding:18px;border-left:4px solid #b99861;background:#fffaf3;border-radius:0 16px 16px 0;font-size:13px;line-height:1.55}.actions{text-align:center;margin:18px}.actions button{border:0;border-radius:999px;padding:12px 18px;font-weight:800}@media(max-width:650px){body{padding:0}.invoice{margin:0;border-radius:0;padding:24px}.top{display:block}.top>div:last-child{margin-top:18px}.brand h1{font-size:27px}}@media print{body{background:white;padding:0}.actions{display:none}.invoice{border:0;margin:0;box-shadow:none}}</style></head><body><div class="invoice"><div class="top"><div class="brand"><img src="${logo}"><div><h1>${biz}</h1><div class="muted">${user}</div></div></div><div><b>Invoice #${String(i.id).slice(-6)}</b><br>Date: ${esc(i.date)}<br>Status: <span class="paid ${i.status==='Paid'?'':'unpaid'}">${esc(i.status)}</span></div></div><div class="box"><b>Bill to</b><p>${esc(i.customer)}</p></div><table><thead><tr><th>Description</th><th class="money">Amount</th></tr></thead><tbody><tr><td>${esc(i.item)}</td><td class="money">${money(i.amount)}</td></tr></tbody></table><div class="payment-summary"><div class="payment-row"><span>Order total</span><b>${money(i.amount)}</b></div><div class="payment-row"><span>Retainer / deposit ${i.depositPaid?'received':'recorded'}</span><b>− ${money(deposit)}</b></div><div class="payment-row"><span>Balance due</span><span>${money(balance)}</span></div></div>${policy?`<div class="policy"><b>Booking & payment policy</b><br>${policy}</div>`:''}<p class="muted">Thank you for supporting a small florist business.</p></div><div class="actions"><button onclick="window.print()">Print / Save PDF</button></div></body></html>`}
function previewInvoice(id){let i=db.invoices.find(x=>x.id===id);if(!i)return;let deposit=Math.min(+i.depositAmount||0,+i.amount||0),balance=Math.max(0,(+i.amount||0)-deposit);invoicePreview.innerHTML=`<div class="preview-sheet"><div class="preview-brand"><img class="invoice-mini-logo" src="${db.settings.logoData||DEFAULT_LOGO}"><div><b>${esc(db.settings.businessName)}</b><small>${esc(db.settings.businessUser)}</small></div></div><hr><p><b>Invoice #${String(i.id).slice(-6)}</b><br>${esc(i.date)} · <span class="pill ${i.status==='Paid'?'done':'notdone'}">${esc(i.status)}</span></p><p><b>Bill to:</b> ${esc(i.customer)}</p><p><b>${esc(i.item)}</b></p><div class="preview-totals"><span>Total <b>${money(i.amount)}</b></span><span>Deposit <b>${money(deposit)}</b></span><span>Balance <b>${money(balance)}</b></span></div><p class="invoice-policy-preview"><b>Policy:</b> ${esc(db.settings.invoicePolicy)}</p><div class="actions"><button onclick="downloadInvoice(${id})">Download invoice</button><button onclick="printInvoice(${id})">Print / Save PDF</button></div></div>`}
function downloadInvoice(id){let i=db.invoices.find(x=>x.id===id);let a=document.createElement('a');a.href=URL.createObjectURL(new Blob([invoiceHTML(i)],{type:'text/html'}));a.download=`invoice-${String(i.id).slice(-6)}-${(db.settings.businessName||'florist').toLowerCase().replace(/[^a-z0-9]+/g,'-')}.html`;a.click();setTimeout(()=>URL.revokeObjectURL(a.href),500)}function printInvoice(id){let i=db.invoices.find(x=>x.id===id);let w=window.open('','_blank');w.document.write(invoiceHTML(i));w.document.close();setTimeout(()=>w.print(),350)}
function drawBar(id,labels,values,title){let c=$(id),ctx=c.getContext('2d'),dpr=window.devicePixelRatio||1,w=c.clientWidth*dpr,h=260*dpr;c.width=w;c.height=h;ctx.scale(dpr,dpr);let W=c.clientWidth,H=260;ctx.clearRect(0,0,W,H);ctx.fillStyle='#fff';ctx.fillRect(0,0,W,H);ctx.fillStyle='#251d18';ctx.font='bold 15px Arial';ctx.fillText(title,16,24);let max=Math.max(1,...values),barW=(W-48)/Math.max(1,values.length);values.forEach((v,i)=>{let bh=(v/max)*(H-78),x=24+i*barW,y=H-34-bh;ctx.fillStyle=i%2?'#eaf1e8':'#f7e6e5';ctx.fillRect(x,y,Math.max(10,barW-10),bh);ctx.fillStyle='#251d18';ctx.font='11px Arial';ctx.fillText(labels[i],x,H-12);ctx.fillText(money(v),x,y-5)})}
function drawLine(id,labels,values,title){let c=$(id),ctx=c.getContext('2d'),dpr=window.devicePixelRatio||1,w=c.clientWidth*dpr,h=260*dpr;c.width=w;c.height=h;ctx.scale(dpr,dpr);let W=c.clientWidth,H=260;ctx.clearRect(0,0,W,H);ctx.fillStyle='#fff';ctx.fillRect(0,0,W,H);ctx.fillStyle='#251d18';ctx.font='bold 15px Arial';ctx.fillText(title,16,24);let max=Math.max(1,...values),pts=values.map((v,i)=>[30+i*(W-60)/Math.max(1,values.length-1),H-38-(v/max)*(H-78)]);ctx.strokeStyle='#2c241f';ctx.lineWidth=3;ctx.beginPath();pts.forEach((p,i)=>i?ctx.lineTo(...p):ctx.moveTo(...p));ctx.stroke();pts.forEach((p,i)=>{ctx.fillStyle='#f7e6e5';ctx.beginPath();ctx.arc(p[0],p[1],5,0,Math.PI*2);ctx.fill();ctx.fillStyle='#251d18';ctx.font='11px Arial';ctx.fillText(labels[i],p[0]-12,H-12);ctx.fillText(money(values[i]),p[0]-20,p[1]-10)})}
function downloadChart(id,name){let a=document.createElement('a');a.href=$(id).toDataURL('image/png');a.download=name+'.png';a.click()}
function generateIdea(){let theme=(ideaTheme.value||'seasonal bouquet').trim(),type=ideaType.value;ideaOutput.innerHTML=`<b>${type} idea:</b> ${theme} from loose stems to finished bouquet.<br><br><b>Hook:</b> Watch me turn ${esc(theme)} into a dreamy floral moment 🌸<br><br><b>Shot list:</b> flower delivery → stem prep → colour palette → arranging → wrapping → final reveal.<br><br><b>Caption:</b> A little behind the scenes of today’s ${esc(theme)} design. Every stem is chosen with care.`}
function render(){normalize();topLogo.src=footerLogo.src=db.settings.logoData||DEFAULT_LOGO;topName.textContent=db.settings.businessName;businessName.value=db.settings.businessName;businessUser.value=db.settings.businessUser;invoicePolicy.value=db.settings.invoicePolicy;customerOptions();calcItems.querySelectorAll('select').forEach(s=>{let v=s.value;s.innerHTML=stockOptions(v)});let sales=db.orders.reduce((a,o)=>a+(+o.price||0),0), costs=db.orders.reduce((a,o)=>a+(+o.cost||0),0), exp=db.expenses.reduce((a,e)=>a+(+e.amount||0),0), doneProfit=db.orders.filter(o=>orderStatus(o)==='Done').reduce((a,o)=>a+(+o.price||0)-(+o.cost||0),0), projected=db.orders.reduce((a,o)=>a+(+o.price||0)-(+o.cost||0),0);sSales.textContent=money(sales);sProfit.textContent=money(doneProfit-exp);sProjected.textContent=money(projected-exp);let low=db.inventory.filter(i=>(+i.qty||0)<=(+i.min||0));lowStock.innerHTML=low.length?low.map(i=>`<p><span class="pill low">${esc(i.name)}: ${i.qty} ${esc(i.unit)}</span></p>`).join(''):'<p class="mini">No low stock alerts.</p>';
let stockTxt=o=>(o.stockUsed||[]).map(s=>`${s.qty} ${s.unit} ${s.name}`).join('<br>')||'—',depositTxt=o=>o.depositPaid?`<span class="pill done">Paid ${money(o.depositAmount)}</span>`:`<span class="pill notdone">Not paid${(+o.depositAmount||0)?' · '+money(o.depositAmount):''}</span>`,balance=o=>Math.max(0,(+o.price||0)-(+o.depositAmount||0));ordersBody.innerHTML=db.orders.map(o=>`<tr><td>${o.date}</td><td>${esc(o.name)}<br><small>${esc(o.notes)}</small></td><td>${esc(o.customerName)}</td><td><span class="pill ${orderStatus(o)==='Done'?'done':'notdone'}">${orderStatus(o)}</span></td><td>${depositTxt(o)}</td><td>${money(balance(o))}</td><td>${money((+o.price||0)-(+o.cost||0))}</td><td>${stockTxt(o)}</td><td><button onclick="invoiceOrder.value='${o.id}';invoiceFromOrder()">Invoice</button> <button class="danger" onclick="del('orders',${o.id})">Delete</button></td></tr>`).join('');ordersCards.innerHTML=db.orders.map(o=>`<div class="mobile-card"><div class="mobile-card-head"><b>${esc(o.name)}</b>${depositTxt(o)}</div><p>${o.date} · ${esc(o.customerName)} · <span class="pill ${orderStatus(o)==='Done'?'done':'notdone'}">${orderStatus(o)}</span></p><div class="mini-metrics"><span>Sale <b>${money(o.price)}</b></span><span>Balance <b>${money(balance(o))}</b></span><span>Profit <b>${money((+o.price||0)-(+o.cost||0))}</b></span></div><p class="mini">Stock: ${stockTxt(o)}</p><button onclick="invoiceOrder.value='${o.id}';invoiceFromOrder()">Create invoice</button> <button class="danger" onclick="del('orders',${o.id})">Delete</button></div>`).join('');
inventoryBody.innerHTML=db.inventory.map(i=>`<tr><td>${esc(i.name)}</td><td>${esc(i.cat)}</td><td><span class="pill ${(+i.qty)<= (+i.min)?'low':''}">${i.qty} ${esc(i.unit)}</span></td><td>${money(i.cost)}</td><td>${money((+i.qty||0)*(+i.cost||0))}</td><td><button onclick="adjInv(${i.id},-1)">-</button> <button onclick="adjInv(${i.id},1)">+</button> <button class="danger" onclick="del('inventory',${i.id})">Delete</button></td></tr>`).join('');inventoryCards.innerHTML=db.inventory.map(i=>`<div class="mobile-card"><b>${esc(i.name)}</b><p>${esc(i.cat)} · <span class="pill ${(+i.qty)<= (+i.min)?'low':''}">${i.qty} ${esc(i.unit)}</span></p><p>Cost ${money(i.cost)} · Value <b>${money((+i.qty||0)*(+i.cost||0))}</b></p><button onclick="adjInv(${i.id},-1)">-</button> <button onclick="adjInv(${i.id},1)">+</button> <button class="danger" onclick="del('inventory',${i.id})">Delete</button></div>`).join('');
expensesBody.innerHTML=db.expenses.map(e=>`<tr><td>${e.date}</td><td>${esc(e.name)}</td><td>${esc(e.cat)}</td><td>${money(e.amount)}</td><td><button class="danger" onclick="del('expenses',${e.id})">Delete</button></td></tr>`).join('');expensesCards.innerHTML=db.expenses.map(e=>`<div class="mobile-card"><b>${esc(e.name)}</b><p>${e.date} · ${esc(e.cat)}</p><p>${money(e.amount)}</p><button class="danger" onclick="del('expenses',${e.id})">Delete</button></div>`).join('');
let sorted=[...db.orders].sort((a,b)=>(a.date||'').localeCompare(b.date||''));calendarBody.innerHTML=sorted.map(o=>`<tr><td>${o.date}</td><td>${esc(o.name)}</td><td>${esc(o.customerName)}</td><td>${orderStatus(o)}</td><td>${money((+o.price||0)-(+o.cost||0))}</td></tr>`).join('');calendarCards.innerHTML=sorted.map(o=>`<div class="mobile-card"><b>${o.date}</b><p>${esc(o.name)} · ${esc(o.customerName)}</p><p>${orderStatus(o)} · ${money((+o.price||0)-(+o.cost||0))}</p></div>`).join('');
customersBody.innerHTML=db.customers.map(c=>`<tr><td>${esc(c.name)}</td><td>${esc(c.phone)}<br><small>${esc(c.email)}</small></td><td>${esc(c.pref)}</td><td>${esc(c.notes)}</td><td><button class="danger" onclick="del('customers',${c.id})">Delete</button></td></tr>`).join('');customersCards.innerHTML=db.customers.map(c=>`<div class="mobile-card"><b>${esc(c.name)}</b><p>${esc(c.phone)} ${esc(c.email)}</p><p>${esc(c.pref)}</p><p>${esc(c.notes)}</p><button class="danger" onclick="del('customers',${c.id})">Delete</button></div>`).join('');
invoiceOrder.innerHTML='<option value="">Choose order</option>'+db.orders.map(o=>`<option value="${o.id}">${esc(o.name)} · ${money(o.price)}</option>`).join('');invoicesBody.innerHTML=db.invoices.map(i=>{let d=Math.min(+i.depositAmount||0,+i.amount||0),b=Math.max(0,(+i.amount||0)-d);return `<tr><td>${i.date}</td><td>${esc(i.customer)}</td><td>${esc(i.item)}</td><td>${money(i.amount)}</td><td>${money(d)} ${i.depositPaid?'✓':''}</td><td><b>${money(b)}</b></td><td>${esc(i.status)}</td><td><button onclick="previewInvoice(${i.id})">Preview</button> <button onclick="downloadInvoice(${i.id})">Download</button> <button onclick="printInvoice(${i.id})">PDF</button> <button class="danger" onclick="del('invoices',${i.id})">Delete</button></td></tr>`}).join('');invoicesCards.innerHTML=db.invoices.map(i=>{let d=Math.min(+i.depositAmount||0,+i.amount||0),b=Math.max(0,(+i.amount||0)-d);return `<div class="mobile-card"><div class="mobile-card-head"><b>${esc(i.customer)}</b><span class="pill ${i.status==='Paid'?'done':'notdone'}">${esc(i.status)}</span></div><p>${i.date} · ${esc(i.item)}</p><div class="mini-metrics"><span>Total <b>${money(i.amount)}</b></span><span>Deposit <b>${money(d)}</b></span><span>Balance <b>${money(b)}</b></span></div><button onclick="previewInvoice(${i.id})">Preview</button> <button onclick="downloadInvoice(${i.id})">Download</button> <button onclick="printInvoice(${i.id})">PDF</button> <button class="danger" onclick="del('invoices',${i.id})">Delete</button></div>`}).join('');
aAverage.textContent=money(db.orders.length?sales/db.orders.length:0);aExpenses.textContent=money(exp);aUnpaid.textContent=money(db.invoices.filter(i=>i.status!=='Paid').reduce((a,i)=>a+(+i.amount||0),0));let month={};db.orders.forEach(o=>{let m=(o.date||today()).slice(0,7);month[m]=(month[m]||0)+(+o.price||0)-(+o.cost||0)});let keys=Object.keys(month).sort().slice(-6);drawLine('profitChart',keys.map(k=>k.slice(5)),keys.map(k=>month[k]),'Profit by month');drawBar('salesExpenseChart',['Sales','Order costs','Expenses'],[sales,costs,exp],'Sales vs expenses');let cat={};db.inventory.forEach(i=>cat[i.cat]=(cat[i.cat]||0)+(+i.qty||0)*(+i.cost||0));drawBar('inventoryChart',Object.keys(cat),Object.values(cat),'Inventory value');let done=db.orders.filter(o=>orderStatus(o)==='Done').length, not=db.orders.length-done;drawBar('statusChart',['Done','Not done'],[done,not],'Order count');let best=Object.entries(month).sort((a,b)=>b[1]-a[1])[0];aBest.textContent=best?`Best tracked month: ${best[0]} with ${money(best[1])} profit before expenses.`:'Add orders to see best month.';aNotes.textContent=`Connected data: ${db.orders.length} orders, ${db.inventory.length} stock items, ${db.customers.length} customers, ${db.invoices.length} invoices and ${db.expenses.length} expenses.`}
setupNav();calcDate.value=orderDate.value=eDate.value=invDate.value=today();addCalcLine();render();


// v1.1.0 premium controls polish: improve mobile date behaviour without changing saved data.
(function(){
  function polishDates(){
    document.querySelectorAll('input[type="date"]').forEach(function(el){
      el.classList.add('fs-date');
      el.setAttribute('aria-label', el.getAttribute('aria-label') || 'Choose date');
      el.addEventListener('focus', function(){ el.parentElement && el.parentElement.classList.add('is-editing-date'); });
      el.addEventListener('blur', function(){ el.parentElement && el.parentElement.classList.remove('is-editing-date'); });
    });
  }
  function polishCards(){
    document.querySelectorAll('.card').forEach(function(card, i){ card.style.animationDelay = Math.min(i*18,180)+'ms'; });
  }
  if(document.readyState==='loading') document.addEventListener('DOMContentLoaded', function(){polishDates(); polishCards();});
  else {polishDates(); polishCards();}
})();
